SELECT count(*) FROM company_name, movie_companies, company_type, title, kind_type, cast_info, movie_info WHERE movie_companies.company_id = company_name.id AND movie_companies.company_type_id = company_type.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id;